#include <stdio.h>
#include <signal.h>
#include <string.h>

volatile sig_atomic_t alarm_count = 0;

void alarm_handler(int sig) {
    (void)sig;
    alarm_count++;
}

int main(void) {
    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = alarm_handler;
    sigemptyset(&sa.sa_mask);
    sigaction(SIGALRM, &sa, NULL);
    printf("SIGALRM handler installed\n");

    /* Programmer une alarme (retourne 0 = pas d'alarme précédente) */
    unsigned int prev = alarm(5);
    printf("Previous alarm: %u\n", prev);

    /* Reprogrammer (retourne le temps restant) */
    prev = alarm(3);
    printf("Remaining from previous: %u (approx)\n", prev > 0 ? 1 : 0);

    /* Annuler */
    prev = alarm(0);
    printf("Cancelled, remaining: %u (approx)\n", prev > 0 ? 1 : 0);

    /* Simuler la réception pour le test */
    raise(SIGALRM);
    raise(SIGALRM);
    printf("Alarms received: %d\n", alarm_count);

    return 0;
}

