 * alarm basique : programmer et annuler
 * ================================================= */
void example_alarm_handler(int sig) { (void)sig; printf("example: ALARM!\n"); }
void example_alarm(void) {
    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = example_alarm_handler;
    sigemptyset(&sa.sa_mask);
    sigaction(SIGALRM, &sa, NULL);
    alarm(10);        /* dans 10s */
    unsigned r = alarm(0); /* annuler */
    printf("example: cancelled with %u remaining\n", r);
    raise(SIGALRM);   /* simuler */
}

